mapper.select:
SELECT m.model_name AS modelName, m.provider AS provider, COUNT(g.id) AS totalCount, COALESCE(SUM(g.tokens_used), 0) AS totalTokens, AVG(g.duration) AS avgDuration FROM sparkit_ai_model m LEFT JOIN sparkit_ai_generation g ON m.id = g.model_id
AND g.create_time >= #{startTime}
AND g.create_time <= #{endTime}
WHERE m.deleted = 0 GROUP BY m.id, m.model_name, m.provider ORDER BY totalCount DESC
